// --- Framer Motion Варианты ---
export const outlineVariants: Variants = {
  unliked: { opacity: 1, scale: 1, rotate: 0, transition: { duration: 0.2 } },
  liked: { opacity: 0, scale: 1.2, rotate: 5, transition: { duration: 0.2 } }
};

export const filledVariants: Variants = {
  unliked: { opacity: 0, scale: 0.8, transition: { duration: 0.2 } },
  liked: { opacity: 1, scale: 1, transition: { type: "tween", ease: "easeOut", duration: 0.3 } }
};

export const ghostVariants: Variants = {
  unliked: {
    opacity: 0, scale: 1, rotate: 0, filter: "blur(0px)", transition: { duration: 0 }
  },
  liked: {
    opacity: [0.8, 0],
    scale: [1, 3.5],
    rotate: [-5, 15],
    filter: ["blur(2px)", "blur(15px)"],
    transition: { duration: 0.8, ease: "easeOut" }
  }
};

const fetcher = (url: string) => fetch(url).then(res => res.json());

interface LikeButtonProps {
  trackId: string | number;
  className?: string;
  size?: number;
  iconVariant?: 'small' | 'large';
  children?: React.ReactNode;
}

export const LikeButton: React.FC<LikeButtonProps> = ({
  trackId,
  className,
  size = 20,
  iconVariant = 'small',
  children
}) => {
  const { mutate } = useSWRConfig();
  const { data, isLoading } = useSWR('/api/favorites/tracks', fetcher);

  const isLiked = data?.tracks?.some((t: any) => t.id === trackId);

  const toggleLike = async (e: React.MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();

    const tracks = data?.tracks || [];
    const optimisticData = {
      ...data,
      tracks: isLiked
        ? tracks.filter((t: any) => t.id !== trackId)
        : [...tracks, { id: trackId }]
    };

    mutate('/api/favorites/tracks', optimisticData, false);

    try {
      const res = await fetch('/api/favorites/tracks', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ trackId })
      });

      if (!res.ok) throw new Error('Failed to toggle like');
      mutate('/api/favorites/tracks');
    } catch (err) {
      console.error(err);
      mutate('/api/favorites/tracks');
    }
  };

  const currentIcon = HEART_ICONS[iconVariant];
  const animateState = isLiked ? "liked" : "unliked";

  const activeColorClass = "text-[var(--like-dominant-color)]";
  const inactiveColorClass = "text-[var(--like-dominant-color)] md:text-current opacity-100 md:opacity-60 hover:opacity-100";

  return (
    <motion.button
      type="button"
      className={cn(styles.button, "transition-colors md:!w-[24px] md:!h-[24px]", className)}
      onClick={toggleLike}
      disabled={isLoading}
      title={isLiked ? "Удалить из избранного" : "Добавить в избранное"}
      whileTap={{ scale: 0.85 }}
    >
      <div className={styles.wrapper} style={{ width: size, height: size }}>
        <motion.div
          className={cn(styles.layer, inactiveColorClass)}
          variants={outlineVariants}
          initial={false}
          animate={animateState}
        >
          {currentIcon.outline}
        </motion.div>
        <motion.div
          className={cn(styles.layer, activeColorClass)}
          variants={filledVariants}
          initial={false}
          animate={animateState}
        >
          {currentIcon.filled}
        </motion.div>
        <motion.div
          className={cn(styles.layer, activeColorClass)}
          variants={ghostVariants}
          initial={false}
          animate={animateState}
        >
          {currentIcon.filled}
        </motion.div>
      </div>
      {children}
    </motion.button>
  );
};